class TestZeroSampleExtended(unittest.TestCase):
    def test_triggers_at_10_days_zero_trades(self):
        fired, msg = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 0}, 10)
        self.assertTrue(fired)
        self.assertIn("momentum-long", msg)
    def test_no_trigger_at_9_days(self):
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 0}, 9)
        self.assertFalse(fired)
    def test_no_trigger_when_disabled(self):
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": False, "trades_lifetime": 0}, 15)
        self.assertFalse(fired)
    def test_no_trigger_when_trades_exist(self):
        fired, _ = heuristic_zero_sample_extended("momentum-long", {"enabled": True, "trades_lifetime": 1}, 15)
        self.assertFalse(fired)
